const kw=$('Get Keyword').first().json;
const organic=(($('Serper Search').first().json||{}).organic)||[];
const hostOf=(u)=>String(u||'').replace(/^https?:\/\//i,'').replace(/^www\./i,'').split(/[\/?#]/)[0].toLowerCase();
// drop non-club hosts: social, news, wiki, federations/FIVB/CEV, results platforms, retail, gov, video, blogs
const blocked=/(facebook|instagram|twitter|x\.com|linkedin|youtube|youtu\.be|tiktok|vimeo|pinterest|reddit|telegram|whatsapp|wikipedia|fandom|wikiwand|volleybox|sofascore|flashscore|transfermarkt|eurosport|worldofvolley|volleyballworld|dataproject\.com|cev\.eu|fivb\.|olympics\.com|maps\.google|google\.|tripadvisor|yelp|amazon|ebay|aliexpress|etsy|booking\.|airbnb|ticketmaster|eventim|ticketportal|ticketpro|\.gov|gazzetta|kicker|sport1|sportschau|news|magazine|blogspot|wordpress\.com|medium\.com|spotify|apple\.com|play\.google|yumpu|issuu|scribd|indeed|glassdoor)/i;
const UA={'User-Agent':'Mozilla/5.0 (compatible; leblovina)'};
const isLive=(c)=>(c>=200&&c<400)||c===401||c===403||c===429;
const get=async(u)=>{try{const r=await this.helpers.httpRequest({method:'GET',url:u,timeout:8000,returnFullResponse:true,ignoreHttpStatusErrors:true,followRedirect:true,headers:UA});return{ok:isLive(r.statusCode||0),status:r.statusCode||0,body:String(r.body||'')};}catch(e){return{ok:false,status:0,body:''};}};
const VB=/(volley|voleib|voley|pallavolo|siatk|odbojk|roplab|r\u00f6plab|tinklin|\u0432\u043e\u043b\u0435|voleybol|lentopallo|volleybal|petosf|\u03c0\u03b5\u03c4\u03bf\u03c3\u03c6|\u03b2\u03bf\u03bb\u03b5)/i;
const seen=new Set(); const cands=[];
for(const r of organic){ const u=r.link; if(!u||!/^https?:\/\//i.test(u))continue; const h=hostOf(u); if(!h||blocked.test(h))continue; if(seen.has(h))continue; seen.add(h); cands.push({url:u,host:h,title:r.title||'',snippet:r.snippet||''}); if(cands.length>=8)break; }
const prepared=[];
for(const c of cands){
  let r=await get('https://'+c.host); let body=r.body;
  if(!r.ok||!body){ r=await get(c.url); body=r.body; if(!r.ok||!body) continue; }
  const grab=(re)=>{const mm=body.match(re);return mm?mm[1]:'';};
  const title=grab(/<title[^>]*>([\s\S]*?)<\/title>/i).replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim().slice(0,200);
  const ogSite=grab(/<meta[^>]+property=["']og:site_name["'][^>]+content=["']([^"']*)["']/i).slice(0,200);
  const h1=grab(/<h1[^>]*>([\s\S]*?)<\/h1>/i).replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim().slice(0,200);
  const head=(title+' '+ogSite+' '+h1).toLowerCase();
  const text=body.replace(/<script[\s\S]*?<\/script>/gi,' ').replace(/<style[\s\S]*?<\/style>/gi,' ').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').slice(0,6000);
  const dom=c.host.replace(/[^a-z0-9]/g,'');
  const hasVB=VB.test(head)||VB.test(text)||VB.test(dom);
  const parked=/(domain (is |may be )?for sale|buy this domain|sedoparking|hugedomains|parking-?lander|godaddy|namecheap|this domain is for sale)/i.test(body);
  const linkCount=(body.match(/<a\b/gi)||[]).length;
  const directoryish=linkCount>180;
  if(!hasVB||parked) continue;   // strict pre-screen: must show volleyball, not parked
  prepared.push({host:c.host,url:'https://'+c.host,title,ogSite,h1,excerpt:text.slice(0,1500),directoryish});
}
return [{json:{kwId:kw.id,keyword:kw.keyword,country:kw.country,lang:kw.lang,resultsCount:organic.length,candidates:prepared}}];

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const prep=$('Prepare candidates').first().json;
const hostOf=(u)=>String(u||'').replace(/^https?:\/\//i,'').replace(/^www\./i,'').split(/[\/?#]/)[0].toLowerCase();
// resolve GGL pseudo-federation id
let GGL=''; try{ const g=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/federations/records',qs:{filter:"fivb_code='GGL'",perPage:1,fields:'id'},headers:pbH,json:true}); GGL=(g.items&&g.items[0]&&g.items[0].id)||''; }catch(e){}
// parse strict classifier output
let results=[]; try{ const resp=$('Classify').first().json; const txt=(resp&&resp.content&&resp.content[0]&&resp.content[0].text)||''; const o=JSON.parse(String(txt).replace(/```json/gi,'').replace(/```/g,'').trim()); results=Array.isArray(o.results)?o.results:[]; }catch(e){}
const byHost={}; for(const r of results){ if(r&&r.host) byHost[hostOf(r.host)]=r; }
const accepted=[]; for(const c of (prep.candidates||[])){ const r=byHost[c.host]; if(r&&String(r.is_club).toLowerCase()==='yes'){ accepted.push({host:c.host,url:c.url,name:String(r.name||c.title||c.host).trim().slice(0,200),city:String(r.city||'').trim().slice(0,100)}); } }
// URL-host dedup against ALL existing clubs (any source)
const existsHost=async(host)=>{ try{ const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/clubs/records',qs:{filter:'website_url~"'+host+'"',perPage:50,fields:'website_url'},headers:pbH,json:true}); return (r.items||[]).some(it=>hostOf(it.website_url)===host); }catch(e){ return false; } };
let newClubs=0, dup=0; const nowIso=new Date().toISOString();
for(const a of accepted){
  if(!a.name){ continue; }
  if(await existsHost(a.host)){ dup++; continue; }
  const club={ federation:GGL, name:a.name, country:prep.country||'', city:a.city||'', website_url:a.url, website_source:'search', website_status:'live', website_confidence:'B', status:'needs_review', dedup_key:'search:'+a.host, notes:'Search-led discovery (keyword: '+prep.keyword+')' };
  let created=null;
  try{ created=await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/clubs/records',headers:pbH,body:club,json:true}); newClubs++; }
  catch(e){ dup++; continue; }   // unique dedup_key conflict => host already held
  try{ await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/scrape_queue/records',headers:pbH,body:{club:created.id,status:'queued',force:false,enqueued_at:nowIso,attempts:0},json:true}); }catch(e){}
}
try{ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/search_keywords/records/'+prep.kwId,headers:pbH,body:{status:'searched',searched_at:nowIso,results_count:prep.resultsCount||0,accepted_count:accepted.length,new_clubs:newClubs,dup_count:dup,notes:''},json:true}); }catch(e){}
return [{json:{kwId:prep.kwId,keyword:prep.keyword,results:prep.resultsCount,candidates:(prep.candidates||[]).length,accepted:accepted.length,new_clubs:newClubs,dup_count:dup}}];
